var e=JSON.parse(`[{"id":"L7_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"으으, 눈 부셔.","JPN":"うう……眩しい……","ENG":"Eergh... It's too bright.","TWN":"唔呃，好刺眼。"},"stage":{"bg":"STADIUM","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"여긴……? 승부는 어떻게 됐지?","JPN":"ここは……？　勝負はどうなったの？","ENG":"Where am I...? What happened to the match?","TWN":"這裡是……？結果誰輸誰贏？"},"stage":{"bg":"STADIUM","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"엇!? 노엘, 라이카!","JPN":"あっ！？　ノエル、ライカ！","ENG":"Huh? Noelle, Laika!","TWN":"嗯？！洛艾兒、萊卡！"},"stage":{"bg":"STADIUM","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"둘 다 정신 좀 차려봐요!","JPN":"二人ともしっかりしてください！","ENG":"Wake up, you two!","TWN":"你們醒醒！"},"stage":{"bg":"STADIUM","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"으으, 여긴 어디예요, 펠리세트?","JPN":"うぅ、ここはどこなんですか、フェリセット？","ENG":"Ooh... Where are we, Félicette?","TWN":"呃呃，這裡是哪裡，費莉塞特？"},"stage":{"bg":"STADIUM","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L14_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"분명 떨어지면서 챔피언을 쏴 갈겼던 것까지는 기억이 나는데…….","JPN":"確か、墜落しながらチャンピオンを撃ちまくってて……","ENG":"I remember falling and shooting the champion...","TWN":"我明明記得我一邊降落一邊掃射冠軍……"},"stage":{"bg":"STADIUM","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L15_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"그 다음에 어떻게 됐더라…….","JPN":"そのあとはどうなったんだっけ……","ENG":"But what happened after that...?","TWN":"然後呢……"},"stage":{"bg":"STADIUM","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L16_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"호, 혹시 그럼 여긴 천국인 걸까요?!","JPN":"じゃ、じゃあもしかしてここは天国なんでしょうか！？","ENG":"D-do you think that we might be in heaven?!","TWN":"難，難道這裡是天堂？！"},"stage":{"bg":"STADIUM","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L17_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"야, 내가 한 번 다녀와 봐서 아는데 천국은 이렇게 안 생겼어.","JPN":"おい、天国には一度行ったことあるけど、こんな場所じゃなかったぞ。","ENG":"Hey, trust me. This looks nothing like heaven. I know because I've been there once already.","TWN":"喂，我之前去過一趟，天堂可不是這個樣子。"},"stage":{"bg":"STADIUM","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L20_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"천국이든 아니든 그런 건 상관없어요.","JPN":"天国だろうが、そうじゃなかろうが構いません。","ENG":"Heaven or not, it doesn't matter to me.","TWN":"是不是天堂都無所謂。"},"stage":{"bg":"STADIUM","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"승부는 어떻게 됐죠? 오지만디아스를 쓰러트렸다면 그걸로 충분해요.","JPN":"勝負はどうなったんですか？　オジマンディアスを倒せたのならそれで十分です。","ENG":"I want to know how the match ended. If I beat Ozymandias, that's enough for me.","TWN":"結果到底誰輸誰贏？我只希望有打敗奧茲曼迪亞斯。"},"stage":{"bg":"STADIUM","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"어……?","JPN":"え……？","ENG":"Huh...?","TWN":"嗯……？"},"stage":{"bg":"STADIUM","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":null,"text":{"KOREA":"잘 싸웠다─! 카나리아 스쿼드─!","JPN":"よくやった─！　カナリア・スクワッド─！","ENG":"Good game–! Canary Squad–!","TWN":"幹得好—！金絲雀小隊—！"},"stage":{"bg":"STADIUM","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":null,"text":{"KOREA":"최고의 명경기였어─! 챔피언─!","JPN":"最高の試合だったぞ─！　チャンピオン─！","ENG":"That was the best match ever–! Champion–!","TWN":"這真是一場有史以來最精彩的比賽—！冠軍—！"},"stage":{"bg":"STADIUM","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":null,"text":{"KOREA":"이대로 명예의 전당까지 가는 거야!!","JPN":"このまま名誉の殿堂まで突き進め！！","ENG":"Now it's straight to the hall of fame!!","TWN":"就這麼一路走向榮譽的殿堂吧！！"},"stage":{"bg":"STADIUM","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"MITCH_NPC_NULL_NULL","text":{"KOREA":"그럼, 그럼! 이 밋치미치는 처음부터 카나리아를 유력한 우승후보라고 생각하고 있었다구!","JPN":"うむうむ！　このミッチーミッチーは最初からカナリアを優勝有力候補だと思っていたとも！","ENG":"Of course!! Mitchie-Mitchie always thought that Canary Squad was a strong contender from the start!","TWN":"沒錯沒錯！米琪一開始就認為金絲雀是最具有潛力的冠軍候選人！"},"stage":{"bg":"STADIUM","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_LAUGH"}}}}]`);export{e as default};